import UIKit
import CryptoSwift

class CryptoWallet {
    var privateKey: Data?
    var publicKey: Data?

    func generateKeys() {
        let (privateKeyData, publicKeyData) = SECP256K1.generateKeyPair()
        self.privateKey = privateKeyData
        self.publicKey = publicKeyData
    }

    func signTransaction(message: String) -> Data? {
        guard let privateKey = privateKey else { return nil }
        let messageData = message.data(using: .utf8)!
        let signature = SECP256K1.sign(messageData, withPrivateKey: privateKey)
        return signature
    }

    func verifySignature(signature: Data, message: String, publicKey: Data) -> Bool {
        let messageData = message.data(using: .utf8)!
        return SECP256K1.verify(signature, forMessage: messageData, withPublicKey: publicKey)
    }
}

class ViewController: UIViewController {
    var wallet: CryptoWallet!

    override func viewDidLoad() {
        super.viewDidLoad()
        wallet = CryptoWallet()
        wallet.generateKeys()

        let transactionMessage = "Send 1 BTC to Alice"
        if let signature = wallet.signTransaction(message: transactionMessage) {
            print("Signature: \(signature.hexString())")
            let isVerified = wallet.verifySignature(signature: signature, message: transactionMessage, publicKey: wallet.publicKey!)
            print("Verification result: \(isVerified)")
        }
    }
}